<?php require_once __DIR__.'/../config/db.php'; require_once __DIR__.'/../config/layout.php'; page_start('Compras','compras'); $assets=$pdo->query("SELECT id,ticker FROM assets ORDER BY ticker")->fetchAll(PDO::FETCH_ASSOC); $rows=$pdo->query("SELECT p.*,a.ticker FROM purchases p JOIN assets a ON a.id=p.asset_id ORDER BY p.buy_date DESC,p.id DESC")->fetchAll(PDO::FETCH_ASSOC); function m($n){return '$'.number_format((float)$n,2);} ?>
<section class="hero"><div><h1>Historial de Compras</h1><p>Registra compras para llevar control de inversión.</p></div></section>
<section class="panel"><h2>Agregar compra</h2><form action="../api/add_purchase.php" method="POST" class="form-row"><select name="asset_id"><?php foreach($assets as $a):?><option value="<?=$a['id']?>"><?=$a['ticker']?></option><?php endforeach;?></select><input type="date" name="buy_date" required><input type="number" step="0.00000001" name="shares" placeholder="Shares" required><input type="number" step="0.00000001" name="buy_price" placeholder="Precio" required><input type="number" step="0.01" name="fee" placeholder="Fee"><input name="note" placeholder="Nota"><button>Agregar</button></form></section>
<section class="panel"><div class="table-wrap"><table><thead><tr><th>Fecha</th><th>Activo</th><th>Shares</th><th>Precio</th><th>Total</th><th>Fee</th><th>Nota</th></tr></thead><tbody><?php foreach($rows as $r):?><tr><td><?=$r['buy_date']?></td><td><b><?=$r['ticker']?></b></td><td><?=$r['shares']?></td><td><?=m($r['buy_price'])?></td><td><?=m($r['shares']*$r['buy_price']+$r['fee'])?></td><td><?=m($r['fee'])?></td><td><?=htmlspecialchars($r['note'])?></td></tr><?php endforeach;?></tbody></table></div></section>
<?php page_end(); ?>
